        'kbd',
        'img',
        '+\x20Add',
        '\x20logic\x20—\x20matching\x20any\x20value\x20within\x20a\x20filter\x20group\x20is\x20enough.\x20Filter\x20groups\x20are\x20then\x20joined\x20with\x20',
